const cfg = $('⚙️ Load Config').item.json;
const raw = cfg.VIRAL_AMPLIFIER_ENABLED;
const enabled = raw === true || String(raw).toLowerCase() === 'true';
return [{ json: { VIRAL_AMPLIFIER_ENABLED: enabled, config: cfg } }];

const config = $('⚙️ Load Config').item.json;
const viewsMin = Number(config.VIRAL_VIEWS_7D_MIN) || 5000;
const engagementMin = Number(config.VIRAL_ENGAGEMENT_MIN) || 0.08;
const baseUrl = (config.WORDPRESS_URL || '').replace(/\/$/, '') || 'https://howtogenie.com';

const ga4Response = $input.first().json;
const rows = ga4Response.rows || [];
const out = [];

for (const row of rows) {
  const pagePath = (row.dimensionValues && row.dimensionValues[0] && row.dimensionValues[0].value) ? row.dimensionValues[0].value : '';
  const pageTitle = (row.dimensionValues && row.dimensionValues[1] && row.dimensionValues[1].value) ? row.dimensionValues[1].value : '';
  const views_7d = Number((row.metricValues && row.metricValues[0] && row.metricValues[0].value) ? row.metricValues[0].value : 0);
  const avg_session_duration = Number((row.metricValues && row.metricValues[1] && row.metricValues[1].value) ? row.metricValues[1].value : 0);
  const engagement_rate = Number((row.metricValues && row.metricValues[2] && row.metricValues[2].value) ? row.metricValues[2].value : 0);
  const bounce_rate = Number((row.metricValues && row.metricValues[3] && row.metricValues[3].value) ? row.metricValues[3].value : 0);

  if (pagePath.length <= 1) continue;
  if (views_7d < viewsMin || engagement_rate < engagementMin) continue;

  const post_url = baseUrl + (pagePath.startsWith('/') ? pagePath : '/' + pagePath);
  const detected_at = new Date().toISOString();
  const viral_score = Math.round((views_7d / 1000) * 0.5 + engagement_rate * 100 * 0.5);

  out.push({
    date: new Date().toISOString().slice(0, 10),
    post_url,
    post_title: pageTitle,
    viral_score,
    views_7d,
    engagement_rate,
    bounce_rate,
    avg_session_duration,
    amplify: true,
    promotion_status: 'pending',
    detected_at,
    row_id: detected_at + post_url
  });
}

return out.map(o => ({ json: o }));
